import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/launcher-screen.B4Y3DSWp.js";import{t as a}from"./chunks/installing-mods.gZ3xnRXE.js";const o=JSON.parse(`{"title":"Installare le Mod","description":"Una guida passo per passo su come installare mod per Fabric.","frontmatter":{"title":"Installare le Mod","description":"Una guida passo per passo su come installare mod per Fabric.","authors":["IMB11"],"files":[]},"headers":[],"relativePath":"it_it/1.21.10/players/installing-mods.md","filePath":"versions/1.21.10/translated/it_it/players/installing-mods.md","lastUpdated":1766682904000}`);var s={name:`it_it/1.21.10/players/installing-mods.md`};function c(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Installare le Mod <a class="header-anchor" href="#h1" aria-label="Permalink to “Installare le Mod”">​</a></h1><p>Questa guida ti aiuterà a installare mod per Fabric usando il Launcher di Minecraft ufficiale.</p><p>Per launcher di terze parti, dovresti consultare la loro documentazione.</p><h2 id="1-download-the-mod" tabindex="-1">1. Scarica la Mod <a class="header-anchor" href="#1-download-the-mod" aria-label="Permalink to “1. Scarica la Mod”">​</a></h2><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Dovresti solo scaricare mod da fonti di cui ti fidi. Per maggiori informazioni su come trovare le mod, vedi la guida <a href="./finding-mods">Trovare Mod Affidabili</a>.</p></div><p>La maggior parte delle mod richiede anche l&#39;API di Fabric, che può essere scaricata da <a href="https://modrinth.com/mod/fabric-api" target="_blank" rel="noreferrer">Modrinth</a> o da <a href="https://curseforge.com/minecraft/mc-mods/fabric-api" target="_blank" rel="noreferrer">CurseForge</a>.</p><p>Quando scarichi delle mod, assicurati che:</p><ul><li>Funzionino nella versione di Minecraft su cui vuoi giocare. Una mod che funziona sulla versione 1.20, per esempio, potrebbe non funzionare sulla versione 1.20.2.</li><li>Siano per Fabric e non per un altro loader di mod.</li><li>Inoltre, che siano per la corretta edizione di Minecraft (Java Edition).</li></ul><h2 id="2-move-the-mod-to-the-mods-folder" tabindex="-1">2. Sposta le Mod nella Cartella <code>mods</code> <a class="header-anchor" href="#2-move-the-mod-to-the-mods-folder" aria-label="Permalink to “2. Sposta le Mod nella Cartella mods”">​</a></h2><p>La cartella mods può essere trovata nelle posizioni seguenti per ciascun sistema operativo.</p><p>Puoi solitamente incollare questi percorsi nella barra degli indirizzi del tuo gestore di file per navigare velocemente alla cartella.</p><div class="vp-code-group"><div class="tabs"><input type="radio" name="group-49" id="tab-50" checked><label data-title="Windows" for="tab-50">Windows</label><input type="radio" name="group-49" id="tab-51"><label data-title="macOS" for="tab-51">macOS</label><input type="radio" name="group-49" id="tab-52"><label data-title="Linux" for="tab-52">Linux</label></div><div class="blocks"><div class="language- active"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>%appdata%\\.minecraft\\mods</span></span></code></pre></div><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>~/Library/Application Support/minecraft/mods</span></span></code></pre></div><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>~/.minecraft/mods</span></span></code></pre></div></div></div><p>Una volta che hai trovato la cartella <code>mods</code>, puoi muovere i file <code>.jar</code> della mod in essa.</p><p><img src="/assets/players/installing-mods.png" alt="Mod installate nella cartella mods" loading="lazy"></p><h2 id="3-you-re-done" tabindex="-1">3. Hai Finito! <a class="header-anchor" href="#3-you-re-done" aria-label="Permalink to “3. Hai Finito!”">​</a></h2><p>Una volta che hai spostato le mod nella cartella <code>mods</code>, puoi aprire il Launcher di Minecraft e selezionare il profilo Fabric dal menu a tendina nell&#39;angolo in basso a sinistra e premere gioca!</p><p><img src="/assets/players/installing-fabric/launcher-screen.png" alt="Launcher di Minecraft con il profilo Fabric selezionato" loading="lazy"></p><h2 id="troubleshooting" tabindex="-1">Risoluzione dei Problemi <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to “Risoluzione dei Problemi”">​</a></h2><p>Se incontri qualsiasi problema nel seguire questa guida, puoi chiedere aiuto nel <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">Discord di Fabric</a> nel canale <code>#player-support</code>.</p><p>Puoi anche tentare di risolvere il problema da solo leggendo le seguenti pagine di risoluzione dei problemi:</p><ul><li><a href="./troubleshooting/crash-reports">Segnalazioni dei Crash</a></li><li><a href="./troubleshooting/uploading-logs">Caricare i Log</a></li></ul>`,21)]])}var l=r(s,[[`render`,c]]);export{o as __pageData,l as default};